const _currentUserId=parseInt(document.body.dataset.userId || '0',10);async function loadUsersList(){const tbody=document.getElementById('admin-users-table');tbody.innerHTML='<tr><td colspan="4" class="text-center text-muted py-3">Загрузка…</td></tr>';const res=await window.Common.csrfFetch('/api/admin/users');if(!res.ok){tbody.innerHTML='<tr><td colspan="4" class="text-danger text-center py-3">Ошибка загрузки</td></tr>';return;}const users=await res.json();const esc=window.Common.escapeHtml;tbody.innerHTML=users.map(u=>{const isSelf=u.id===_currentUserId;return `<tr><td class="text-muted small">${u.id}</td><td><b>${esc(u.username)}</b></td><td><span class="badge ${u.is_admin ? 'bg-danger':'bg-secondary'}">${u.is_admin ? 'Админ':'Юзер'}</span></td><td>${isSelf ? '<span class="text-muted small">—</span>':`<button class="btn btn-sm btn-outline-danger" onclick="deleteUserTrigger(${u.id},'${esc(u.username)}')">Удалить</button>`}</td></tr>`;}).join('');}function deleteUserTrigger(userId,name){window.Common.askConfirmation(`Удалить аккаунт «${name}» навсегда?`,async()=>{const res=await window.Common.csrfFetch(`/api/admin/delete_user/${userId}`,{method:'DELETE'});const data=await res.json();window.Common.showToast(data.message,!res.ok);loadUsersList();});}document.getElementById('adminCreateUserForm').addEventListener('submit',async e=>{e.preventDefault();const btn=document.getElementById('createUserBtn');btn.disabled=true;btn.textContent='Создание…';try{const res=await window.Common.csrfFetch('/api/admin/add_user',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:document.getElementById('newUsername').value,password:document.getElementById('newPassword').value,is_admin:document.getElementById('isAdminCheck').checked,})});const data=await res.json();if(res.ok){window.Common.showToast(data.message);e.target.reset();loadUsersList();}else{window.Common.showSystemMessage(data.message,true);}}finally{btn.disabled=false;btn.textContent='Создать';}});loadUsersList();